public void initFromSalesTable(SalesTable salesTable, SalesParmTable _salesParmTable)
{
    next initFromSalesTable(salesTable, _salesParmTable);

    // CompanyBankAccountPay

    BankAccountTable    bankAccountTable = BankAccountTable::find(this.custTable_InvoiceAccount().KPMGCommon_CompanyBankAccountIdPay);
    CustTable           custTable_InvoiceAccount = this.custTable_InvoiceAccount();

    if (CustPaymModeTable::find(salesTable.paymMode).KPMGCommon_TransferPayment && custTable_InvoiceAccount.KPMGCommon_CompanyBankAccountIdPay)
        this.KPMGCommon_BankAccountCompanyPay = strFmt("%1 %2 %3", bankAccountTable.Name, bankAccountTable.IBAN, bankAccountTable.SWIFTNo);

    this.KPMGCommon_LIVAArticle = this.KPMGCommon_ReturnTextLIVAArticle(salesTable, this);
}

public KPMGCommon_LIVAArticle KPMGCommon_ReturnTextLIVAArticle(SalesTable _salesTable, CustInvoiceJour  _custInvoiceJour)
{
    TmpTaxWorkTrans         tmpTaxWorkTrans;
    TaxTable                taxTable;
    SalesTotals salesTotals = SalesTotals::construct(_salesTable, SalesUpdate::All);
    KPMGCommon_LIVAArticle  lIVAArticle;

     salesTotals.calc();
     tmpTaxWorkTrans = salesTotals.tax().tmpTaxWorkTrans();

    while select TaxCode from tmpTaxWorkTrans
            group by TaxCode
    {
        if (lIVAArticle)
            continue;

        taxTable = TaxTable::find(tmpTaxWorkTrans.TaxCode);
        if (!lIVAArticle && (taxTable.KPMGCommon_LIVAArticle_ES || taxTable.KPMGCommon_LIVAArticle_EN))
        {
            if (_custInvoiceJour.LanguageId == CompanyInfo::find().LanguageId)
            {
                lIVAArticle = taxTable.KPMGCommon_LIVAArticle_ES;
            }
            else
            {
                lIVAArticle = taxTable.KPMGCommon_LIVAArticle_EN;
            }
        }
    }

    return lIVAArticle;
}
